parameters.code:
// Parse Gemini response and extract JSON
const geminiResponse = $input.all()[0].json;

let aiAnalysis = {
  risk_level: 'unknown',
  confidence_score: 0,
  recommended_actions: [],
  analysis_summary: '',
  is_critical: false
};

try {
  // Extract text from Gemini response
  if (geminiResponse.candidates && geminiResponse.candidates[0]) {
    const content = geminiResponse.candidates[0].content.parts[0].text;

    // Try to parse JSON from response
    const jsonMatch = content.match(/\{[^{}]*\}/g);
    if (jsonMatch) {
      const parsed = JSON.parse(jsonMatch[0]);
      aiAnalysis = {
        ...aiAnalysis,
        ...parsed,
        is_critical: parsed.risk_level === 'critical'
      };
    }
  }
} catch (error) {
  console.log('Error parsing AI response:', error.message);
}

return {
  ...aiAnalysis,
  timestamp: new Date().toISOString(),
  threat_data: {
    ip_address: $input.all()[0].body.ip_address,
    abuseipdb_score: $input.all()[1].json.data?.abuseConfidenceScore || 0,
    virustotal_malicious: $input.all()[2].json.data?.last_analysis_stats?.malicious || 0
  }
};

